import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  project: 'flowise-code-gen',
  riskProfile: 'high'
});

const flowWithVex = codeGenFlow.withCallbacks([
  {
    type: 'onChainEnd',
    callback: async (output) => {
      await vex.verify({
        sessionId: 'code-gen-' + Date.now(),
        data: output,
        checks: ['code_safety', 'syntax_valid', 'no_secrets']
      });
    }
  }
]);

const safeSandboxTool = {
  ...sandboxTool,
  func: async (code: string) => {
    const safetyCheck = await vex.verify({
      data: code,
      checks: [
        'code_safety',
        'no_eval_exec',
        'no_network_calls',
        'dependency_safety'
      ],
      riskProfile: 'high'
    });

    if (!safetyCheck.pass) {
      throw new Error(`Safety violation: ${safetyCheck.issues}`);
    }

    return await originalSandbox(code);
  }
};

const vexSession = await vex.createSession({
  useCase: 'code_generation',
  riskProfile: 'high',
  metadata: { flowId: flow.id }
});

const tracedFlow = codeGenFlow.withCallbacks([
  {
    type: 'onChainStart',
    callback: () => vexSession.startTrace('code-gen-cycle')
  },
  {
    type: 'onToolStart',
    callback: (tool) => vexSession.logEvent('tool_call', { tool })
  },
  {
    type: 'onChainEnd',
    callback: async (output) => {
      const result = await vexSession.verifyOutput(output);
      if (!result.pass) {
        throw new Error('Vex verification failed');
      }
    }
  }
]);
